import Foundation

// MARK: - Protocol (injectable for tests)

public protocol FileWatching: Sendable {
    func changes() -> AsyncStream<Data>
}

// MARK: - Production implementation

/// Watches a single file using FS events (DispatchSource) with a polling fallback.
///
/// Hybrid strategy: a `DispatchSource.makeFileSystemObjectSource` watches for
/// `.write` events. A fallback timer re-checks every `pollInterval` seconds in
/// case FS events are missed (network mounts, fd invalidation after atomic
/// replace). Duplicate reads are suppressed by comparing modification dates.
public final class UsagesFileWatcher: FileWatching, @unchecked Sendable {
    private let path: String
    private let pollInterval: TimeInterval
    private let logger: FileLogger

    public static let defaultPollSeconds: TimeInterval = 30

    public init(
        path: String,
        pollInterval: TimeInterval = UsagesFileWatcher.defaultPollSeconds,
        logger: FileLogger = Loggers.app
    ) {
        self.path = path
        self.pollInterval = pollInterval
        self.logger = logger
    }

    public func changes() -> AsyncStream<Data> {
        let path = self.path
        let pollInterval = self.pollInterval
        let logger = self.logger

        return AsyncStream { continuation in
            let watcherTask = Task {
                // Protects lastModDate from concurrent access (GCD handler + cooperative pool)
                let lock = NSLock()
                var lastModDate: Date?
                var dispatchSource: DispatchSourceFileSystemObject?
                var fileDescriptor: Int32 = -1
                // Prevents repeated warnings when the file stays unreadable across poll ticks
                var contentReadFailed = false

                func emitIfChanged() {
                    lock.lock()
                    defer { lock.unlock() }

                    let attrs: [FileAttributeKey: Any]
                    do {
                        attrs = try FileManager.default.attributesOfItem(atPath: path)
                    } catch {
                        if !contentReadFailed {
                            logger.log(.warning, "FileWatcher: attributesOfItem failed on \(path): \(error)")
                            contentReadFailed = true
                        }
                        return
                    }
                    guard let modDate = attrs[.modificationDate] as? Date else {
                        return
                    }
                    if modDate != lastModDate {
                        if let data = FileManager.default.contents(atPath: path) {
                            lastModDate = modDate
                            contentReadFailed = false
                            continuation.yield(data)
                        } else {
                            if !contentReadFailed {
                                logger.log(.warning, "FileWatcher: contents(atPath:) returned nil for \(path)")
                                contentReadFailed = true
                            }
                        }
                    }
                }

                func openSource() -> (DispatchSourceFileSystemObject, Int32)? {
                    let fd = open(path, O_EVTONLY)
                    guard fd >= 0 else {
                        logger.log(.warning, "FileWatcher: open() failed on \(path): \(String(cString: strerror(errno)))")
                        return nil
                    }
                    // If cancelled before resume(), the cancel handler won't fire — guard against fd leak
                    guard !Task.isCancelled else {
                        close(fd)
                        return nil
                    }
                    let source = DispatchSource.makeFileSystemObjectSource(
                        fileDescriptor: fd,
                        eventMask: [.write, .delete, .rename],
                        queue: DispatchQueue.global(qos: .utility)
                    )
                    source.setEventHandler { emitIfChanged() }
                    source.setCancelHandler { close(fd) }
                    source.resume()
                    return (source, fd)
                }

                emitIfChanged()

                if let (src, fd) = openSource() {
                    dispatchSource = src
                    fileDescriptor = fd
                    logger.log(.debug, "FileWatcher: FS events active on \(path)")
                } else {
                    logger.log(.warning, "FileWatcher: FS source unavailable on \(path), using poll-only mode")
                }

                while !Task.isCancelled {
                    // CancellationError swallowed intentionally; checked on next loop iteration
                    try? await Task.sleep(nanoseconds: UInt64(pollInterval * 1_000_000_000))
                    guard !Task.isCancelled else { break }

                    emitIfChanged()

                    // Re-establish FS watcher if fd went stale (file was replaced)
                    let fileExists = FileManager.default.fileExists(atPath: path)
                    let fdValid = fileDescriptor >= 0 && fcntl(fileDescriptor, F_GETFD) != -1
                    if fileExists && !fdValid {
                        dispatchSource?.cancel()
                        if let (src, fd) = openSource() {
                            dispatchSource = src
                            fileDescriptor = fd
                            logger.log(.debug, "FileWatcher: re-opened FS source on \(path)")
                        }
                    }
                }

                dispatchSource?.cancel()
                continuation.finish()
            }

            continuation.onTermination = { _ in watcherTask.cancel() }
        }
    }
}

import Foundation
import Testing
@testable import AIUsagesTrackersLib

// MARK: - Test doubles

/// A mock FileWatching that lets tests push arbitrary Data payloads.
struct MockFileWatcher: FileWatching {
    let stream: AsyncStream<Data>
    let continuation: AsyncStream<Data>.Continuation

    init() {
        var cont: AsyncStream<Data>.Continuation!
        stream = AsyncStream { cont = $0 }
        continuation = cont
    }

    func changes() -> AsyncStream<Data> { stream }

    func send(_ data: Data) { continuation.yield(data) }
    func finish() { continuation.finish() }
}

/// A clock fixed at a given date, for deterministic remaining-time formatting.
struct FixedClock: ClockProvider {
    let date: Date
    init(_ date: Date) { self.date = date }
    func now() -> Date { date }
}

// MARK: - Helpers

private func makeUsagesJSON(
    vendor: String = "claude",
    account: String = "user@example.com",
    isActive: Bool = true,
    metrics: [[String: Any]] = []
) -> Data {
    let entry: [String: Any] = [
        "vendor": vendor,
        "account": account,
        "isActive": isActive,
        "metrics": metrics,
    ]
    let root: [String: Any] = ["usages": [entry]]
    return try! JSONSerialization.data(withJSONObject: root)
}

private func timeWindowMetric(
    name: String = "session",
    resetAt: String = "2026-04-17T15:00:00Z",
    windowDurationMinutes: Int = 300,
    usagePercent: Int = 42
) -> [String: Any] {
    [
        "type": "time-window",
        "name": name,
        "resetAt": resetAt,
        "windowDurationMinutes": windowDurationMinutes,
        "usagePercent": usagePercent,
    ]
}

private func payAsYouGoMetric(
    name: String = "monthly",
    currentAmount: Double = 12.50,
    currency: String = "USD"
) -> [String: Any] {
    [
        "type": "pay-as-you-go",
        "name": name,
        "currentAmount": currentAmount,
        "currency": currency,
    ]
}

// MARK: - Tests

@Suite("UsageStore formatting")
struct UsageStoreFormattingTests {

    private var referenceDate: Date {
        let f = ISO8601DateFormatter()
        return f.date(from: "2026-04-17T12:47:00Z")!
    }

    @MainActor
    @Test("default menuBarText is fallback")
    func defaultIsFallback() {
        let watcher = MockFileWatcher()
        let store = UsageStore(fileWatcher: watcher)
        #expect(store.menuBarText == "--")
    }

    @MainActor
    @Test("single time-window metric formats correctly")
    func singleTimeWindow() async throws {
        let watcher = MockFileWatcher()
        let clock = FixedClock(referenceDate)
        let store = UsageStore(fileWatcher: watcher, clock: clock, countdownRefreshSeconds: 999)
        store.start()

        // resetAt is 2h13m in the future from referenceDate
        let data = makeUsagesJSON(metrics: [
            timeWindowMetric(name: "session", resetAt: "2026-04-17T15:00:00Z", usagePercent: 48),
        ])
        watcher.send(data)

        // Let the async stream deliver
        try await Task.sleep(nanoseconds: 50_000_000)

        #expect(store.menuBarText == "S 48% 2h 13m")
        store.stop()
    }

    @MainActor
    @Test("multiple time-window metrics joined by pipe")
    func multipleTimeWindows() async throws {
        let watcher = MockFileWatcher()
        let clock = FixedClock(referenceDate)
        let store = UsageStore(fileWatcher: watcher, clock: clock, countdownRefreshSeconds: 999)
        store.start()

        let data = makeUsagesJSON(metrics: [
            timeWindowMetric(name: "session", resetAt: "2026-04-17T15:00:00Z", usagePercent: 48),
            timeWindowMetric(name: "weekly", resetAt: "2026-04-23T21:00:00Z", usagePercent: 7),
        ])
        watcher.send(data)
        try await Task.sleep(nanoseconds: 50_000_000)

        #expect(store.menuBarText == "S 48% 2h 13m | W 7% 6d 8h 13m")
        store.stop()
    }

    @MainActor
    @Test("pay-as-you-go metrics are ignored")
    func payAsYouGoIgnored() async throws {
        let watcher = MockFileWatcher()
        let clock = FixedClock(referenceDate)
        let store = UsageStore(fileWatcher: watcher, clock: clock, countdownRefreshSeconds: 999)
        store.start()

        let data = makeUsagesJSON(metrics: [
            payAsYouGoMetric(),
        ])
        watcher.send(data)
        try await Task.sleep(nanoseconds: 50_000_000)

        // No time-window metrics → fallback
        #expect(store.menuBarText == "--")
        store.stop()
    }

    @MainActor
    @Test("mixed metrics: only time-window rendered")
    func mixedMetrics() async throws {
        let watcher = MockFileWatcher()
        let clock = FixedClock(referenceDate)
        let store = UsageStore(fileWatcher: watcher, clock: clock, countdownRefreshSeconds: 999)
        store.start()

        let data = makeUsagesJSON(metrics: [
            timeWindowMetric(name: "session", resetAt: "2026-04-17T15:00:00Z", usagePercent: 48),
            payAsYouGoMetric(),
        ])
        watcher.send(data)
        try await Task.sleep(nanoseconds: 50_000_000)

        #expect(store.menuBarText == "S 48% 2h 13m")
        store.stop()
    }

    @MainActor
    @Test("resetAt in the past shows 0m")
    func resetAtInPast() async throws {
        let watcher = MockFileWatcher()
        let clock = FixedClock(referenceDate)
        let store = UsageStore(fileWatcher: watcher, clock: clock, countdownRefreshSeconds: 999)
        store.start()

        let data = makeUsagesJSON(metrics: [
            timeWindowMetric(name: "session", resetAt: "2026-04-17T10:00:00Z", usagePercent: 100),
        ])
        watcher.send(data)
        try await Task.sleep(nanoseconds: 50_000_000)

        #expect(store.menuBarText == "S 100% 0m")
        store.stop()
    }

    @MainActor
    @Test("resetAt exactly now shows 0m")
    func resetAtExactlyNow() async throws {
        let watcher = MockFileWatcher()
        let clock = FixedClock(referenceDate)
        let store = UsageStore(fileWatcher: watcher, clock: clock, countdownRefreshSeconds: 999)
        store.start()

        let data = makeUsagesJSON(metrics: [
            timeWindowMetric(name: "session", resetAt: "2026-04-17T12:47:00Z", usagePercent: 50),
        ])
        watcher.send(data)
        try await Task.sleep(nanoseconds: 50_000_000)

        #expect(store.menuBarText == "S 50% 0m")
        store.stop()
    }
}

@Suite("UsageStore graceful degradation")
struct UsageStoreDegradationTests {

    @MainActor
    @Test("malformed JSON falls back to --")
    func malformedJSON() async throws {
        let watcher = MockFileWatcher()
        let store = UsageStore(fileWatcher: watcher, countdownRefreshSeconds: 999)
        store.start()

        watcher.send("not json".data(using: .utf8)!)
        try await Task.sleep(nanoseconds: 50_000_000)

        #expect(store.menuBarText == "--")
        store.stop()
    }

    @MainActor
    @Test("no active Claude entry falls back to --")
    func noActiveClaude() async throws {
        let watcher = MockFileWatcher()
        let store = UsageStore(fileWatcher: watcher, countdownRefreshSeconds: 999)
        store.start()

        let data = makeUsagesJSON(isActive: false, metrics: [
            timeWindowMetric(),
        ])
        watcher.send(data)
        try await Task.sleep(nanoseconds: 50_000_000)

        #expect(store.menuBarText == "--")
        store.stop()
    }

    @MainActor
    @Test("wrong vendor falls back to --")
    func wrongVendor() async throws {
        let watcher = MockFileWatcher()
        let store = UsageStore(fileWatcher: watcher, countdownRefreshSeconds: 999)
        store.start()

        let data = makeUsagesJSON(vendor: "other", metrics: [
            timeWindowMetric(),
        ])
        watcher.send(data)
        try await Task.sleep(nanoseconds: 50_000_000)

        #expect(store.menuBarText == "--")
        store.stop()
    }

    @MainActor
    @Test("active Claude entry with empty metrics falls back to --")
    func emptyMetrics() async throws {
        let watcher = MockFileWatcher()
        let store = UsageStore(fileWatcher: watcher, countdownRefreshSeconds: 999)
        store.start()

        let data = makeUsagesJSON(metrics: [])
        watcher.send(data)
        try await Task.sleep(nanoseconds: 50_000_000)

        #expect(store.menuBarText == "--")
        store.stop()
    }

    @MainActor
    @Test("subsequent valid data recovers from error state")
    func recoveryAfterError() async throws {
        let watcher = MockFileWatcher()
        let f = ISO8601DateFormatter()
        let clock = FixedClock(f.date(from: "2026-04-17T12:00:00Z")!)
        let store = UsageStore(fileWatcher: watcher, clock: clock, countdownRefreshSeconds: 999)
        store.start()

        watcher.send("bad".data(using: .utf8)!)
        try await Task.sleep(nanoseconds: 50_000_000)
        #expect(store.menuBarText == "--")

        let data = makeUsagesJSON(metrics: [
            timeWindowMetric(name: "session", resetAt: "2026-04-17T13:00:00Z", usagePercent: 10),
        ])
        watcher.send(data)
        try await Task.sleep(nanoseconds: 50_000_000)
        #expect(store.menuBarText == "S 10% 1h")

        store.stop()
    }
}

@Suite("UsageStore lifecycle")
struct UsageStoreLifecycleTests {

    @MainActor
    @Test("start is idempotent")
    func startIdempotent() {
        let watcher = MockFileWatcher()
        let store = UsageStore(fileWatcher: watcher, countdownRefreshSeconds: 999)
        store.start()
        store.start() // second call should be no-op
        store.stop()
    }

    @MainActor
    @Test("stop is idempotent")
    func stopIdempotent() {
        let watcher = MockFileWatcher()
        let store = UsageStore(fileWatcher: watcher, countdownRefreshSeconds: 999)
        store.start()
        store.stop()
        store.stop() // second call should be no-op
    }

    @MainActor
    @Test("stop before start is safe")
    func stopBeforeStart() {
        let watcher = MockFileWatcher()
        let store = UsageStore(fileWatcher: watcher, countdownRefreshSeconds: 999)
        store.stop()
    }
}

@Suite("UsageStore remaining time formatting edge cases")
struct UsageStoreRemainingTimeTests {

    @MainActor
    @Test("exactly 1 day remaining")
    func exactlyOneDay() async throws {
        let watcher = MockFileWatcher()
        let f = ISO8601DateFormatter()
        let clock = FixedClock(f.date(from: "2026-04-17T00:00:00Z")!)
        let store = UsageStore(fileWatcher: watcher, clock: clock, countdownRefreshSeconds: 999)
        store.start()

        let data = makeUsagesJSON(metrics: [
            timeWindowMetric(name: "daily", resetAt: "2026-04-18T00:00:00Z", usagePercent: 0),
        ])
        watcher.send(data)
